```class Solution {
    public long mostPoints(int[][] questions) {
        int n = questions.length;
        int[][] dp = new int[n][n];

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                dp[i][j] = Math.max(questions[i][0], questions[j][1]);
            }
        }

        int maxPoints = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                maxPoints = Math.max(maxPoints, dp[i][j]);
            }
        }

        return maxPoints;
    }
}
```

